using System.Text;

namespace Microsoft.Diagnostics.DataContractReader.DataGenerator;

internal static class Emitter
{
    // Generated files declare a file-scoped namespace inside
    // Microsoft.Diagnostics.DataContractReader.* so these short names resolve
    // via parent-namespace lookup. The using directives below cover
    // TypeHandle (in ...Contracts) explicitly.
    private const string Target = "Target";
    private const string TargetPointer = "TargetPointer";
    private const string TypeHandleType = "TypeHandle";
    private const string IDataInterface = "IData";

    private const string RootNamespace = "Microsoft.Diagnostics.DataContractReader";

    public static string Emit(CdacTypeModel model)
    {
        StringBuilder sb = new();
        sb.AppendLine("// <auto-generated/>");
        sb.AppendLine("#nullable enable");
        sb.AppendLine();
        sb.AppendLine("using Microsoft.Diagnostics.DataContractReader;");
        sb.AppendLine("using Microsoft.Diagnostics.DataContractReader.Contracts;");
        sb.AppendLine();
        if (!string.IsNullOrEmpty(model.Namespace))
        {
            sb.AppendLine($"namespace {model.Namespace};");
            sb.AppendLine();
        }

        sb.AppendLine($"partial class {model.ClassName}");
        sb.AppendLine("{");

        // The class advertises a managed identity (TypeHandle + FullyQualifiedName)
        // whenever ManagedFullName is set, regardless of whether field offsets come
        // from a native descriptor or from the managed type source.
        bool hasManagedIdentity = model.ManagedFullName is not null;

        // Field offsets come from the managed type source only when no native
        // descriptor was specified. With a native descriptor, the cdac descriptor
        // already anchors offsets at the object pointer (header included).
        bool useNativeDescriptor = model.DataTypeEnumValue is not null || model.DescriptorName is not null;
        bool useManagedDescriptor = !useNativeDescriptor && hasManagedIdentity;

        if (hasManagedIdentity)
        {
            sb.AppendLine($"    private const string FullyQualifiedName = \"{model.ManagedFullName}\";");
            sb.AppendLine();
            sb.AppendLine($"    public static {TypeHandleType} TypeHandle({Target} target)");
            sb.AppendLine($"        => target.Contracts.ManagedTypeSource.GetTypeHandle(FullyQualifiedName);");
            sb.AppendLine();
        }

        sb.AppendLine($"    public {TargetPointer} Address {{ get; }}");
        sb.AppendLine();

        if (model.ImplementsIData)
        {
            EmitConstructor(sb, model, useManagedDescriptor);
            EmitCreate(sb, model);
        }

        EmitWriteBackMethods(sb, model, useManagedDescriptor);

        foreach (MemberModel member in model.Members)
        {
            switch (member.Kind)
            {
                case MemberKind.StaticAddress:
                    EmitStaticAddressMethod(sb, member);
                    break;
                case MemberKind.StaticReference:
                    EmitStaticReferenceMethod(sb, member);
                    break;
                case MemberKind.ThreadStaticAddress:
                    EmitThreadStaticAddressMethod(sb, member);
                    break;
            }
        }

        sb.AppendLine("}");
        return sb.ToString();
    }

    /// <summary>
    /// Emits a <c>Write{Name}(Target target, T value)</c> method for each
    /// settable <c>[Field]</c> property on a <c>StoreAddress = true</c> class.
    /// Only supported for primitive integer and bool read kinds; other types
    /// would need <c>WriteNUIntField</c>/<c>WritePointerField</c> support,
    /// which we can add later.
    /// </summary>
    private static void EmitWriteBackMethods(StringBuilder sb, CdacTypeModel model, bool useManagedDescriptor)
    {
        // Write-back is only meaningful when the class uses the native
        // descriptor (not the managed type source, which is read-only).
        if (useManagedDescriptor)
        {
            return;
        }

        foreach (MemberModel member in model.Members)
        {
            if (member.Kind != MemberKind.Field || !member.HasSetter)
            {
                continue;
            }

            if (member.ReadKind != FieldReadKind.Primitive && member.ReadKind != FieldReadKind.Bool)
            {
                continue;
            }

            // RawOffset-based fields don't have a descriptor entry to write through.
            if (member.RawOffset is not null)
            {
                continue;
            }

            EmitWriteBackMethod(sb, model, member);
        }
    }

    private static void EmitWriteBackMethod(StringBuilder sb, CdacTypeModel model, MemberModel member)
    {
        string descriptorName = model.DataTypeEnumValue ?? model.DescriptorName ?? string.Empty;
        string typeAccess = $"target.GetTypeInfo(\"{descriptorName}\")";

        string propType = Shorten(member.PropertyOrReturnTypeFqn)!;
        string descName = $"\"{member.DescriptorOrFieldName}\"";

        sb.AppendLine($"    public void Write{member.Name}({Target} target, {propType} value)");
        sb.AppendLine("    {");
        sb.AppendLine($"        {Target}.TypeInfo type = {typeAccess};");
        if (member.ReadKind == FieldReadKind.Bool)
        {
            sb.AppendLine($"        target.WriteField<byte>(Address, type, {descName}, (byte)(value ? 1 : 0));");
        }
        else
        {
            string? typeArg = Shorten(member.DataTypeArgumentFqn);
            sb.AppendLine($"        target.WriteField<{typeArg}>(Address, type, {descName}, value);");
        }
        sb.AppendLine($"        {member.Name} = value;");
        sb.AppendLine("    }");
        sb.AppendLine();
    }

    private static void EmitConstructor(StringBuilder sb, CdacTypeModel model, bool useManagedDescriptor)
    {
        // Hook: a `partial void OnInit(Target, TargetPointer)` the user may
        // implement to perform reads that don't fit the declarative attribute
        // surface (e.g. variable-count loops, raw-offset reads, or values
        // computed from other fields). If no implementation is provided the
        // C# compiler elides both the call site and the signature.
        sb.AppendLine($"    partial void OnInit({Target} target, {TargetPointer} address);");
        sb.AppendLine();

        sb.AppendLine($"    public {model.ClassName}({Target} target, {TargetPointer} address)");
        sb.AppendLine("    {");

        bool needsTypeInfo = HasInstanceDescriptorMembers(model);

        if (needsTypeInfo)
        {
            if (useManagedDescriptor)
            {
                sb.AppendLine($"        {Target}.TypeInfo type = target.Contracts.ManagedTypeSource.GetTypeInfo(FullyQualifiedName);");
                if (model.IsValueType)
                {
                    sb.AppendLine($"        {TargetPointer} dataAddress = address;");
                }
                else
                {
                    sb.AppendLine($"        {TargetPointer} dataAddress = address + target.GetTypeInfo(\"Object\").Size!.Value;");
                }
            }
            else
            {
                string descriptorName = model.DataTypeEnumValue ?? model.DescriptorName ?? string.Empty;
                sb.AppendLine($"        {Target}.TypeInfo type = target.GetTypeInfo(\"{descriptorName}\");");
            }

            sb.AppendLine();
        }

        string addr = useManagedDescriptor ? "dataAddress" : "address";

        sb.AppendLine("        Address = address;");

        foreach (MemberModel member in model.Members)
        {
            EmitMemberAssignment(sb, member, addr);
        }

        sb.AppendLine();
        sb.AppendLine("        OnInit(target, address);");
        sb.AppendLine("    }");
        sb.AppendLine();
    }

    private static void EmitCreate(StringBuilder sb, CdacTypeModel model)
    {
        sb.AppendLine($"    static {model.ClassName} {IDataInterface}<{model.ClassName}>.Create({Target} target, {TargetPointer} address)");
        sb.AppendLine($"        => new {model.ClassName}(target, address);");
        sb.AppendLine();
    }

    private static bool HasInstanceDescriptorMembers(CdacTypeModel model)
    {
        foreach (MemberModel member in model.Members)
        {
            // Members with a hardcoded RawOffset don't need the descriptor.
            if (member.RawOffset is not null)
            {
                continue;
            }

            if (member.Kind == MemberKind.Field
                || member.Kind == MemberKind.FieldAddress
                || member.Kind == MemberKind.InstanceDataStart)
            {
                return true;
            }
        }

        return false;
    }

    private static void EmitMemberAssignment(StringBuilder sb, MemberModel member, string addrVar)
    {
        switch (member.Kind)
        {
            case MemberKind.Field:
            {
                string readExpr = member.RawOffset is int offset
                    ? RawOffsetReadExpression(member, offset)
                    : ReadExpression(member, addrVar);
                if (member.IsOptional)
                {
                    sb.AppendLine($"        {member.Name} = type.Fields.ContainsKey(\"{member.DescriptorOrFieldName}\")");
                    sb.AppendLine($"            ? {readExpr}");
                    sb.AppendLine($"            : default({Shorten(member.PropertyOrReturnTypeFqn)});");
                }
                else
                {
                    sb.AppendLine($"        {member.Name} = {readExpr};");
                }
                break;
            }
            case MemberKind.FieldAddress:
                sb.AppendLine($"        {member.Name} = {addrVar} + (ulong)type.Fields[\"{member.DescriptorOrFieldName}\"].Offset;");
                break;
            case MemberKind.InstanceDataStart:
                sb.AppendLine($"        {member.Name} = {addrVar} + type.Size!.Value;");
                break;
        }
    }

    private static string RawOffsetReadExpression(MemberModel member, int offset)
    {
        string? typeArg = Shorten(member.DataTypeArgumentFqn);
        string addr = $"address + {offset}";
        string readMethod = member.LittleEndian ? "ReadLittleEndian" : "Read";
        return member.ReadKind switch
        {
            FieldReadKind.Primitive => $"target.{readMethod}<{typeArg}>({addr})",
            FieldReadKind.Bool => $"target.{readMethod}<byte>({addr}) != 0",
            FieldReadKind.Pointer => $"target.ReadPointer({addr})",
            FieldReadKind.NUInt => $"target.ReadNUInt({addr})",
            FieldReadKind.CodePointer => $"target.ReadCodePointer({addr})",
            FieldReadKind.DataInPlace => $"target.ProcessedData.GetOrAdd<{typeArg}>({addr})",
            _ => $"default({Shorten(member.PropertyOrReturnTypeFqn)})",
        };
    }

    private static string ReadExpression(MemberModel member, string addrVar)
    {
        string descName = $"\"{member.DescriptorOrFieldName}\"";
        string? typeArg = Shorten(member.DataTypeArgumentFqn);
        return member.ReadKind switch
        {
            FieldReadKind.Primitive => $"target.ReadField<{typeArg}>({addrVar}, type, {descName})",
            FieldReadKind.Bool => $"target.ReadField<byte>({addrVar}, type, {descName}) != 0",
            FieldReadKind.Pointer => $"target.ReadPointerField({addrVar}, type, {descName})",
            FieldReadKind.NUInt => $"target.ReadNUIntField({addrVar}, type, {descName})",
            FieldReadKind.CodePointer => $"target.ReadCodePointerField({addrVar}, type, {descName})",
            FieldReadKind.DataInPlace => $"target.ReadDataField<{typeArg}>({addrVar}, type, {descName})",
            FieldReadKind.DataPointer => $"target.ProcessedData.GetOrAdd<{typeArg}>(target.ReadPointerField({addrVar}, type, {descName}))",
            _ => $"default({Shorten(member.PropertyOrReturnTypeFqn)})",
        };
    }

    private static void EmitStaticAddressMethod(StringBuilder sb, MemberModel member)
    {
        sb.AppendLine($"    public static partial {TargetPointer} {member.Name}({Target} target)");
        sb.AppendLine($"        => target.Contracts.ManagedTypeSource.GetStaticFieldAddress(FullyQualifiedName, \"{member.DescriptorOrFieldName}\");");
        sb.AppendLine();
    }

    private static void EmitStaticReferenceMethod(StringBuilder sb, MemberModel member)
    {
        sb.AppendLine($"    public static partial {TargetPointer} {member.Name}({Target} target)");
        sb.AppendLine($"        => target.Contracts.ManagedTypeSource.TryGetStaticFieldAddress(FullyQualifiedName, \"{member.DescriptorOrFieldName}\", out {TargetPointer} address)");
        sb.AppendLine($"            ? target.ReadPointer(address)");
        sb.AppendLine($"            : {TargetPointer}.Null;");
        sb.AppendLine();
    }

    private static void EmitThreadStaticAddressMethod(StringBuilder sb, MemberModel member)
    {
        sb.AppendLine($"    public static partial {TargetPointer} {member.Name}({Target} target, {TargetPointer} thread)");
        sb.AppendLine($"        => target.Contracts.ManagedTypeSource.GetThreadStaticFieldAddress(FullyQualifiedName, \"{member.DescriptorOrFieldName}\", thread);");
        sb.AppendLine();
    }

    public static string HintNameFor(CdacTypeModel model)
    {
        string ns = string.IsNullOrEmpty(model.Namespace) ? "Global" : model.Namespace.Replace('.', '_');
        return $"{ns}.{model.ClassName}.g.cs";
    }

    /// <summary>
    /// Strips redundant <c>global::</c> and <c>Microsoft.Diagnostics.DataContractReader.</c>
    /// prefixes from a fully-qualified type name. The generated file's namespace
    /// and the using directives at the top make these prefixes redundant.
    /// </summary>
    private static string? Shorten(string? fqn)
    {
        if (fqn is null)
        {
            return null;
        }

        const string GlobalPrefix = "global::";
        if (fqn.StartsWith(GlobalPrefix, System.StringComparison.Ordinal))
        {
            fqn = fqn.Substring(GlobalPrefix.Length);
        }

        const string RootPrefix = RootNamespace + ".";
        if (fqn.StartsWith(RootPrefix, System.StringComparison.Ordinal))
        {
            fqn = fqn.Substring(RootPrefix.Length);
        }

        return fqn;
    }
}
